INSERT INTO prompt_hint_items (id, hint_id, item_type, content, meaning_ko, usage_tip_ko, example_en, expression_family, display_order, is_active)
VALUES
('hint-rtn-26-1-item-1', 'hint-rtn-26-1', 'FRAME', 'Before bed, I usually ...', '잠들기 전에는 저는 보통 ...', '루틴을 자연스럽게 시작할 때 쓰세요.', 'Before bed, I usually make tea and get ready for tomorrow.', 'ROUTINE_STARTER', 1, 1),
('hint-rtn-26-2-item-1', 'hint-rtn-26-2', 'WORD', 'stretch', '가볍게 몸을 풀다', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I stretch for a few minutes before bed.', 'BEDTIME_ROUTINE', 1, 1),
('hint-rtn-26-2-item-2', 'hint-rtn-26-2', 'WORD', 'journal', '일기를 쓰다', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I journal for a few minutes at night.', 'BEDTIME_ROUTINE', 2, 1),
('hint-rtn-26-2-item-3', 'hint-rtn-26-2', 'WORD', 'alarm', '알람', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I always check my alarm before I sleep.', 'BEDTIME_ROUTINE', 3, 1),
('hint-rtn-26-2-item-4', 'hint-rtn-26-2', 'WORD', 'pajamas', '잠옷', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I change into my pajamas after washing up.', 'BEDTIME_ROUTINE', 4, 1),
('hint-rtn-26-2-item-5', 'hint-rtn-26-2', 'WORD', 'sleepy', '졸린', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'By then, I already feel sleepy.', 'BEDTIME_FEELING', 5, 1),
('hint-rtn-26-2-item-6', 'hint-rtn-26-2', 'WORD', 'habit', '습관', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'A small habit can shape the rest of the day.', 'ROUTINE_BONUS', 6, 1),
('hint-rtn-26-2-item-7', 'hint-rtn-26-2', 'WORD', 'regularly', '규칙적으로', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I do it regularly, even on busy days.', 'ROUTINE_BONUS', 7, 1),
('hint-rtn-26-2-item-8', 'hint-rtn-26-2', 'WORD', 'sequence', '순서', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'The sequence is simple, so I can keep it easily.', 'ROUTINE_BONUS', 8, 1),
('hint-rtn-26-3-item-1', 'hint-rtn-26-3', 'PHRASE', 'brush my teeth', '양치하다', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I brush my teeth and wash my face before I sleep.', 'BEDTIME_ACTION', 1, 1),
('hint-rtn-26-3-item-2', 'hint-rtn-26-3', 'PHRASE', 'turn off the lights', '불을 끄다', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I turn off the lights around eleven.', 'BEDTIME_ACTION', 2, 1),
('hint-rtn-26-3-item-3', 'hint-rtn-26-3', 'PHRASE', 'get ready for tomorrow', '내일을 준비하다', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I get ready for tomorrow before I sleep.', 'BEDTIME_PREP', 3, 1),
('hint-rtn-26-3-item-4', 'hint-rtn-26-3', 'PHRASE', 'calm down', '마음을 가라앉히다', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'Reading helps me calm down before bed.', 'BEDTIME_FEELING', 4, 1),
('hint-rtn-26-4-item-1', 'hint-rtn-26-4', 'FRAME', 'First, I ...', '먼저 저는 ...', '첫 행동을 말할 때 좋아요.', 'First, I wash up and sit down for a moment.', 'ROUTINE_STRUCTURE', 1, 1),
('hint-rtn-26-4-item-2', 'hint-rtn-26-4', 'PHRASE', 'after that', '그다음에', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'After that, I check a few things for tomorrow.', 'ROUTINE_STRUCTURE', 2, 1),
('hint-rtn-26-4-item-3', 'hint-rtn-26-4', 'PHRASE', 'before I ...', '~하기 전에', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'Before I go to sleep, I set my alarm.', 'ROUTINE_STRUCTURE', 3, 1),
('hint-rtn-26-4-item-4', 'hint-rtn-26-4', 'FRAME', 'It helps me feel ...', '그렇게 하면 저는 ...한 기분이 들어요.', '느낌을 덧붙이면 더 자연스러워져요.', 'It helps me feel calm and ready for the next day.', 'ROUTINE_FEELING', 4, 1),
('hint-rtn-27-1-item-1', 'hint-rtn-27-1', 'FRAME', 'Before bed, I usually ...', '잠들기 전에는 저는 보통 ...', '루틴을 자연스럽게 시작할 때 쓰세요.', 'Before bed, I usually make tea and get ready for tomorrow.', 'ROUTINE_STARTER', 1, 1),
('hint-rtn-27-2-item-1', 'hint-rtn-27-2', 'WORD', 'stretch', '가볍게 몸을 풀다', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I stretch for a few minutes before bed.', 'BEDTIME_ROUTINE', 1, 1),
('hint-rtn-27-2-item-2', 'hint-rtn-27-2', 'WORD', 'journal', '일기를 쓰다', 'Routine 카테고리의 Before Bed 질문에서 자연스럽게 써 보세요.', 'I journal for a few minutes at night.', 'BEDTIME_ROUTINE', 2, 1),
